        IT_1 = 1
      ELSE
        IT_1 = 0
      ENDIF

! 1030:[select] Two Input Selector 
      IF (IT_1 .EQ. RTCI(NRTCI)) THEN
         Volt_dip = RT_6
      ELSE
         Volt_dip = RT_7
      ENDIF
      NRTCI = NRTCI + 1
!

! 1040:[select] Two Input Selector 
      IF (NINT(Volt_dip) .EQ. RTCI(NRTCI)) THEN
         RT_42 = RT_25
      ELSE
         RT_42 = RT_41
      ENDIF
      NRTCI = NRTCI + 1
!

! 1050:[edge] Edge Detector 
!  Edge_Detector
      IF (Volt_dip .LT. STORF(NSTORF)) THEN
         IT_8 = 1
      ELSE IF (Volt_dip .GT. STORF(NSTORF)) THEN
         IT_8 = 0
      ELSE
         IT_8 = 0
      ENDIF
      STORF(NSTORF) = Volt_dip
      NSTORF = NSTORF + 1
!

! 1060:[inv] Interpolated Logic Inverter 
      IF (NINT(Volt_dip) .NE. 0) THEN
         No_dip = 0
      ELSE
         No_dip = 1
      ENDIF

! 1070:[monostable] Interpolated Monostable MultiVibrator 
!
      RVD2_1(1) = FLOAT(IT_8)
      RVD2_1(2) = 0.0
      CALL EMTDC_XMSTAB(0,Thid,RVD2_1,RVD2_2)
      IT_9 = NINT(RVD2_2(1))


! 1080:[integral] Interpolated Integrator 
      RVD1_1 = RTCF(NRTCF) ! Initial Output
      NRTCF = NRTCF + 1
      RVD2_1(1) = RT_31
      RVD2_1(2) = 0.0
      RVD2_2(1) = FLOAT(No_dip)
      RVD2_2(2) = 0.0
      TimeFreeze = EMTDC_XINT(0, 0, 1, RVD1_1, 1.0, 0.0, -100.0, 100.0, &
     &RVD2_2, RVD2_1)

! 1090:[compar] Two Input Comparator 
!
      CALL EMTDC_X2COMP(0,0,TimeFreeze,deltaT,0.0,0.0,1.0,RVD2_1)
      RT_32 = RVD2_1(1)

! 1100:[logic_mult] Multiple Input Logic Gate 
!
! Multi input AND gate
!
      IF ( (NINT(RT_32) .NE. 0) .AND. (NINT(Volt_dip) .NE. 0) ) THEN
        Freeze = 1
      ELSE
        Freeze = 0
      ENDIF

! 1110:[inv] Interpolated Logic Inverter 
      IF (Freeze .NE. 0) THEN
         NoFreeze = 0
      ELSE
         NoFreeze = 1
      ENDIF

! 1120:[logic_mult] Multiple Input Logic Gate 
!
! Multi input AND gate
!
      IF ( (NINT(Volt_dip) .NE. 0) .AND. (NoFreeze .NE. 0) ) THEN
        offline = 1
      ELSE
        offline = 0
      ENDIF

! 1130:[inv] Interpolated Logic Inverter 
      IF (offline .NE. 0) THEN
         online = 0
      ELSE
         online = 1
      ENDIF

! 1140:[mult] Multiplier 
      RT_20 = RT_23 * REAL(NoFreeze)

! 1150:[pi_ctlr] PI Controller \w Interpolation 
      RVD1_1 = RTCF(NRTCF)
      NRTCF = NRTCF + 1
      RVD2_1(1) = RT_20
      RVD2_1(2) = 0.0
      RT_21 = EMTDC_XPI(0,Kqp,Tqi,Vmin,Vmax,RVD1_1,RVD2_1)

! 1160:[sandhdefn] Sample and Hold 
!  Sample and Hold
      CALL SANDH2(RT_21,Freeze,  1,  RT_28)

! 1170:[mult] Multiplier 
      State2 = REAL(IT_9) * RT_45

! 1180:[select] Two Input Selector 
      IF (NINT(Vflag) .EQ. RTCI(NRTCI)) THEN
         Vvflag = RT_28
      ELSE
         Vvflag = RT_29
      ENDIF
      NRTCI = NRTCI + 1
!

! 1190:[hardlimit] Hard Limiter 
!  IO_Lolim_Hard_Limit
      IF (Vmin .LE. Vmax) THEN
        Vstar = LIMIT(Vmin, Vmax, Vvflag)
      ELSE
        Vstar = Vvflag
        IF (STORL(NSTORL) .EQV. .FALSE.) THEN
          CALL EMTDC_WARN(ICALL_NO,369036775,1,"Lower limit is more than&
     & the upper limit, limits not enforced.")
          STORL(NSTORL) = .TRUE.
        ENDIF
      ENDIF
      NSTORL = NSTORL + 1
!

! 1200:[sumjct] Summing/Differencing Junctions 
      RT_19 = - Vt_filt + Vstar

! 1210:[mult] Multiplier 
      RT_15 = RT_19 * REAL(NoFreeze)

! 1220:[sandhdefn] Sample and Hold 
!  Sample and Hold
      CALL SANDH2(RT_17,Freeze,  1,  RT_22)

! 1230:[sandhdefn] Sample and Hold 
!  Sample and Hold
      CALL SANDH2(RT_36,Freeze,  1,  RT_5)

! 1240:[realpole] Real Pole 
!  Real_Pole
      RT_2 = REALPOLE(0,1,1,1.0,Tpord,RT_5,0.0,Pmin,Pmax)

! 1250:[div] Divider 
!
      IF (ABS(RT_3) .LT. 1.0E-10) THEN
         IF (RT_3 .LT. 0.0)  THEN
            RT_1 = -1.0E10 * RT_2
         ELSE
            RT_1 =  1.0E10 * RT_2
         ENDIF
      ELSE
         RT_1 = RT_2 / RT_3
      ENDIF
!

! 1260:[sandhdefn] Sample and Hold 
!  Sample and Hold
      CALL SANDH2(RT_1,Freeze,  1,  RT_34)

! 1270:[select] Two Input Selector 
      IF (NINT(State2) .EQ. RTCI(NRTCI)) THEN
         Iqinj = Iqfrz
      ELSE
         Iqinj = RT_42
      ENDIF
      NRTCI = NRTCI + 1
!

! 1280:[pi_ctlr] PI Controller \w Interpolation 
      RVD1_1 = RTCF(NRTCF)
      NRTCF = NRTCF + 1
      RVD2_1(1) = RT_15
      RVD2_1(2) = 0.0
      RT_16 = EMTDC_XPI(0,Kvp,Tvi,Iqmin,Iqmax,RVD1_1,RVD2_1)

! 1290:[sandhdefn] Sample and Hold 
!  Sample and Hold
      CALL SANDH2(RT_16,Freeze,  1,  RT_13)

! 1300:[realpole] Real Pole 
!  Real_Pole
      RT_14 = REALPOLE(0,1,1,1.0,tiq,RT_22,0.0,Iqmin,Iqmax)

! 1310:[select] Two Input Selector 
      IF (NINT(Qflag) .EQ. RTCI(NRTCI)) THEN
         Iqo_qflag = RT_13
      ELSE
         Iqo_qflag = RT_14
      ENDIF
      NRTCI = NRTCI + 1
!

! 1320:[sumjct] Summing/Differencing Junctions 
      RT_11 = + Iqinj + Iqo_qflag

! 1330:[hardlimit] Hard Limiter 
!  IO_Lolim_Hard_Limit
      IF (Iqmin .LE. Iqmax) THEN
        RT_12 = LIMIT(Iqmin, Iqmax, RT_11)
      ELSE
        RT_12 = RT_11
        IF (STORL(NSTORL) .EQV. .FALSE.) THEN
          CALL EMTDC_WARN(ICALL_NO,1816351607,1,"Lower limit is more tha&
     &n the upper limit, limits not enforced.")
          STORL(NSTORL) = .TRUE.
        ENDIF
      ENDIF
      NSTORL = NSTORL + 1
!

! 1340:[gain] Gain Block 
!  Gain
      RT_30 = 1.0 * RT_12

! 1350:[mult] Multiplier 
      Iqcmd = RT_30 * REAL(online)

! 1360:[CurrentLimit_1_2_1_1]  
      CALL CurrentLimit_1_2_1_1Dyn(Ivdl1, Ivdl2, Iqmax, Iqmin, Ipmin, Ip&
     &max, Imax, Iqcmd, Ipcmd, PQflag)


! 1370:[hardlimit] Hard Limiter 
!  IO_Lolim_Hard_Limit
      IF (Ipmin .LE. Ipmax) THEN
