        ENDIF
      ENDIF
      NSTORL = NSTORL + 1
!

! 1380:[mult] Multiplier 
      Ipcmd = RT_35 * REAL(online)

! 1390:[inv] Interpolated Logic Inverter 
      IF (NINT(Volt_dip) .NE. 0) THEN
         IT_2 = 0
      ELSE
